import "./Footer.css";

/**
 * Footer
 * Minimal brand strip with Indian & Tamil Nadu wedding photos.
 */
export default function Footer() {
  const year = new Date().getFullYear();

  const footerPhotos = [
    {
      src: "https://images.unsplash.com/photo-1606216174052-f90c55f6c04d?w=400&h=400&q=85&fm=jpg&fit=crop",
      alt: "Indian Couple Traditional Wedding",
    },
    {
      src: "https://images.unsplash.com/photo-1606216174087-ee341ca57cfc?w=400&h=400&q=85&fm=jpg&fit=crop",
      alt: "Bridal Portrait in Red Saree",
    },
    {
      src: "https://images.unsplash.com/photo-1606216174235-9c0c7be87159?w=400&h=400&q=85&fm=jpg&fit=crop",
      alt: "Couple in Traditional Attire",
    },
    {
      src: "https://images.unsplash.com/photo-1606216174066-8d74fac5e3a1?w=400&h=400&q=85&fm=jpg&fit=crop",
      alt: "Indian Wedding Engagement Couple",
    },
    {
      src: "https://images.unsplash.com/photo-1606216174043-eddc92a68e5f?w=400&h=400&q=85&fm=jpg&fit=crop",
      alt: "Groom in Sherwani with Bride",
    },
    {
      src: "https://images.unsplash.com/photo-1606216174116-c6ca65b83e4d?w=400&h=400&q=85&fm=jpg&fit=crop",
      alt: "South Indian Wedding Celebration",
    },
  ];

  return (
    <footer className="footer">
      <div className="footer__content">
        <div className="footer__text">
          <span className="footer__brand">
            Ayyan Studio <em>Classics</em>
          </span>
          <span className="footer__info">
            © {year} · South Indian Wedding Specialists
          </span>
        </div>

        <div className="footer__gallery">
          {footerPhotos.map((photo, idx) => (
            <div key={idx} className="footer__gallery-item">
              <img 
                src={photo.src} 
                alt={photo.alt} 
                loading="lazy"
                decoding="async"
                onError={(e) => {
                  e.target.style.display = 'none';
                  e.target.parentElement.style.backgroundColor = 'rgba(201, 168, 92, 0.15)';
                }}
              />
            </div>
          ))}
        </div>
      </div>
    </footer>
  );
}
